let dimensionString = "";
let jsonObject = queries.fetchConfigDetails.data.Dimensions;

Object.keys(jsonObject).forEach(key => {
  if(!jsonObject[key].dimension_name.includes("LEGACY_")) {
    dimensionString += `L${parseInt(key)+1}: ${jsonObject[key].dimension_name} (${jsonObject[key].type.replace('TYPE_', '').toLowerCase()}), `;
  }
});
return dimensionString.slice(0, dimensionString.length-2);
